function run(listaNomes, resposta) {
    const numeroEscolhido = parseInt(String(resposta).replace(/\D+/g, ""));
    if (isNaN(numeroEscolhido)) {
        return false;
    }

    const nomesArray = listaNomes
        .split("\n")
        .map(linha => linha.replace(/^\d+\.\s*/, "").trim())
        .filter(linha => linha !== "");

    const indice = numeroEscolhido - 1;
    if (indice >= 0 && indice < nomesArray.length) {
        return nomesArray[indice];
    }

    return false;
}

function run(manualTriggerRes) {
    if (!manualTriggerRes || manualTriggerRes === "null") {
        return JSON.stringify({ "name": "Erro: Resposta Vazia", "action": "error" });
    }

    try {
        var data = (typeof manualTriggerRes === 'object') ? manualTriggerRes : JSON.parse(manualTriggerRes);

        var intent = data.action || "confirm";
        var finalQueue = (intent === "alter") ? "Recepção Central / Suporte" : (data.queue || "Recepção Central / Suporte");

        return JSON.stringify({
            "action": intent,
            "queue": finalQueue,
            "name": data.patientName || "Paciente",
            "cpf": data.patientCPF || "",
            "birth": data.patientBirthdate || ""
        });
    } catch (e) {
        return JSON.stringify({ "name": "Erro: Falha no Parse", "action": "error" });
    }
}

function run(manualTriggerRes) {
    if (!manualTriggerRes || manualTriggerRes === "null" || manualTriggerRes === "") {
        return "WAIT";
    }
    try {
        var data = (typeof manualTriggerRes === 'object') ? manualTriggerRes : JSON.parse(manualTriggerRes);
        // Se o nome do paciente não existe no JSON, ainda não está pronto
        return (data.patientName) ? "READY" : "WAIT";
    } catch (e) {
        return "WAIT";
    }
}
